    "field.sync_offline": "Frakoblet - endringer lagres og synkroniseres.",
    "field.sync_online": "Tilkoblet - endringer synkroniseres automatisk.",
    "info.boq.title": "Om kalkyler",
    "info.boq.body": "En mengdefortegnelse lister hver arbeidspost med mengde og enhetspris og summeres til prosjektets totalsum. Kalkyler her henter fra kostnadsdatabasen og BIM-mengder og mater videre validering, budsjettet og anbudspakkene.",
    "info.match-elements.title": "Match elementer mot kostnader",
    "info.match-elements.body": "Prissett en BIM- eller CAD-modell ved Ă„ matche elementene mot en regional kostnadskatalog, og skriv deretter resultatet direkte inn i prosjektet som en mengdefortegnelse. Veiviseren grupperer elementer, rangerer kostnadskandidater med semantisk sĂžk og lar deg bekrefte treff fĂžr de blir til faktiske BOQ-poster med mengder og enhetspriser.",
    "info.ai-estimate.title": "AI-kalkyle",
    "info.ai-estimate.body": "GjĂžr tekst, bilder, PDF-er, regneark eller CAD- og BIM-filer om til et strukturert kostnadsestimat med mengder, enheter og enhetspriser. Match linjer mot kostnadsdatabasen og lagre resultatet som en mengdefortegnelse pĂ„ ethvert prosjekt.",
    "info.costs.title": "Kostnadsdatabase",
    "info.costs.body": "Bla gjennom enhetspriser og sammensatte priser for materialer, arbeid og utstyr pĂ„ tvers av regionale kataloger som CWICR, BKI og RSMeans, eller legg til dine egne. Priser bĂŠrer med seg valuta og klassifisering, sĂ„ poster du henter inn i en mengdefortegnelse mater direkte inn i kostnads- og fremdriftssammenstillingen.",
    "info.catalog.title": "Ressurskatalog",
    "info.catalog.body": "Bla gjennom og prissett de grunnleggende byggesteinene for kalkyler - enkeltmaterialer, arbeidssatser og utstyrskostnader - hentet fra de regionale CWICR-databasene eller dine egne importer. Vedlikehold disse prisene her, og de mater sammensatte poster, enhetspriser i mengdefortegnelsen og kostnadsmatching pĂ„ tvers av alle prosjekter, med samlede justeringer for inflasjon, region og gruppe pĂ„ ett sted.",
    "info.assemblies.title": "Om sammensatte poster",
    "info.assemblies.body": "Sammensatte poster er gjenbrukbare kostnadsoppskrifter som samler materialer, arbeid og utstyr i Ă©n sammensatt enhetspris, for eksempel en armert betongvegg med betong, armering, forskaling og arbeid. Bruk en sammensatt post pĂ„ en BOQ-post for Ă„ fylle ut komponentkostnadene automatisk og holde prisene ensartede i prosjektet.",
    "info.takeoff.title": "PDF-mengdeuttak",
    "info.takeoff.body": "Last opp PDF-tegninger for Ă„ mĂ„le arealer, lengder og antall, eller la AI hente ut elementer med mengder. Valgte poster flyter direkte inn i mengdefortegnelsen din og forblir knyttet til prosjektets kostnad og fremdrift.",
    "info.dwg-takeoff.title": "DWG-mengdeuttak",
    "info.dwg-takeoff.body": "Last opp DWG- eller DXF-tegninger for Ă„ se entitetene, slĂ„ lag av og pĂ„ og mĂ„le arealer, lengder og antall direkte pĂ„ tegningen. Knytt mĂ„linger til BOQ-poster slik at mengder flyter inn i kostnadsestimatet ditt sammen med BIM og den kanoniske modellen.",
    "info.bim.title": "BIM-modellviser",
    "info.bim.body": "Utforsk konverterte CAD- og BIM-modeller i 3D, inspiser elementegenskaper og mengder og filtrer etter etasje, kategori eller fagfelt. Knytt elementer til BOQ-poster for Ă„ drive mengdeuttak, kostnad og fremdrift fra den kanoniske modellen.",
    "info.geo.title": "Geo Hub",
    "info.geo.body": "Se alle prosjektene dine som nĂ„ler pĂ„ en delt 3D-globus. Forankre et prosjekt pĂ„ adresse eller koordinater, og hopp fra kartplasseringen inn i mengdefortegnelsen, BIM-modellene og resten av de kanoniske prosjektdataene.",
    "info.coordination.title": "Nav for modellkoordinering",
    "info.coordination.body": "Dette dashbordet samler de fĂždererte BIM-modellene dine, kollisjonsresultater, regelpakkekontroller og BCF-aktivitet for det aktive prosjektet i Ă©n helseoversikt. Bruk hurtighandlingene til Ă„ triagere kollisjoner, administrere fĂžderasjoner eller kjĂžre samsvarsregler, alt koblet tilbake til den kanoniske modellen.",
    "info.bim-federations.title": "BIM-fĂžderasjoner",
    "info.bim-federations.body": "Grupper beslektede BIM-modeller med felles opprinnelse, som arkitektur, konstruksjon og installasjoner, i ett koordinert sett. Fra en fĂžderasjon kan du administrere medlemmer og Ă„pne hver modell i 3D-viseren, og holde den kanoniske modellen ensartet pĂ„ tvers av fagfelt for mengdeuttak, mengdefortegnelse og kostnadsarbeid.",
    "info.clash.title": "Kollisjonskontroll",
    "info.clash.body": "KjĂžr geometriske interferens- og klaringskontroller pĂ„ tvers av de kanoniske BIM-modellene i dette prosjektet, og triager hver kollisjon etter fagfelt, status og alvorlighetsgrad. LĂžste saker lenker direkte til 3D-viseren og eksporteres til BCF for koordinering med resten av plattformen.",
    "info.contracts.title": "Om kontrakter",
    "info.contracts.body": "Administrer de kommersielle avtalene bak prosjektene dine, fra et vunnet anbud til sluttoppgjĂžret. Hver kontrakt bĂŠrer sin egen typebevisste betalingsplan, tilbakehold og avdragskrav og lenker til endringsordrer, mengdefortegnelse og kostnadsstammen slik at kontraktssummen fĂžlger med resten av plattformen.",
    "info.subcontractors.title": "UnderentreprenĂžrregister",
    "info.subcontractors.body": "FĂžlg din prekvalifiserte forsyningskjede her: forsikrings- og sertifikatstatus, underentrepriseomfang, betalingssĂžknader, tilbakehold og prestasjonsvurderinger. Godkjente firmaer kan inviteres til anbudspakker og bindes av kontrakter, der prekvalifisering og avkall regulerer tildeling og betaling.",
    "info.bid-management.title": "Om anbudsstyring",
    "info.bid-management.body": "KjĂžr anbud fra ende til ende: samle omfang i anbudspakker, inviter underentreprenĂžrer, samle inn prissatte tilbud og sammenlign dem side om side fĂžr du tildeler. Pakker kan hente fra prosjektets BOQ, og en tildeling flyter direkte inn i Kontrakter.",
    "info.tendering.title": "Om anbud",
    "info.tendering.body": "Bygg anbudspakker fra en BOQ, send dem til underentreprenĂžrer og sammenlign tilbudene du mottar side om side. Arbeidsflyten kjĂžrer Utkast, Utsendt, Samler inn, Vurderer, Tildelt. Ă tildele en vinner skriver de avtalte prisene tilbake til BOQ-en og forbereder en utkast-innkjĂžpsordre i InnkjĂžp.",
    "info.variations.title": "Om endringsordrer",
    "info.variations.body": "Administrer kontraktsendringer pĂ„ et aktivt prosjekt: endringsvarsler, prissatte forespĂžrsler, avtalte ordrer, regningsarbeidssedler og krav om fristforlengelse. Godkjente ordrer fĂžrer kostnads- og fremdriftspĂ„virkningen videre til kontraktens sluttoppgjĂžr og rulles opp i Ăkonomi.",
    "global_search.placeholder": "SĂžk etter hva som helst - BOQ-poster, tegninger, oppgaver, risikoer, BIM-elementer...",
    "global_search.scope_project": "Bare gjeldende prosjekt",
    "global_search.hint": "Begynn Ă„ skrive for Ă„ sĂžke pĂ„ tvers av alle prosjektmoduler etter betydning, ikke nĂžyaktig treff.",
    "global_search.searching": "SĂžker...",
    "global_search.no_results": "Ingen treff ennĂ„ - prĂžv en annen formulering",
    "global_search.footer_hint": "Semantisk sĂžk drevet av vektorembeddinger",

